//! In-tool host-approval policy: a case-insensitive host allowlist.

/// Whether a host may be contacted without approval.
pub enum HostDecision {
    Allow,
    Ask,
}

/// Case-insensitive host allowlist.
pub struct NetworkPolicy {
    allow: Vec<String>,
}

impl NetworkPolicy {
    pub fn new(hosts: &[String]) -> Self {
        let allow = hosts
            .iter()
            .map(|h| h.trim().to_ascii_lowercase())
            .filter(|h| !h.is_empty())
            .collect();
        Self { allow }
    }

    pub fn decide(&self, host: &str) -> HostDecision {
        // TODO: implement the allowlist matching rules. Currently asks for everything.
        let _ = (&self.allow, host);
        HostDecision::Ask
    }
}
